{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://local/problem-tree.schema.json",
  "title": "Problem Tree Analysis",
  "description": "Structured requirement analysis and problem-tree decomposition for a single problem statement.",
  "type": "object",
  "additionalProperties": false,
  "required": ["meta", "summary", "requirements", "problemTree"],
  "properties": {
    "meta": {
      "type": "object",
      "additionalProperties": false,
      "required": ["sourceFile", "generatedAt", "title"],
      "properties": {
        "sourceFile": { "type": "string", "description": "Path of the analyzed file." },
        "generatedAt": { "type": "string", "description": "ISO-8601 timestamp of generation." },
        "title": { "type": "string", "description": "Short title inferred from the problem statement." }
      }
    },
    "summary": {
      "type": "string",
      "description": "One-paragraph restatement of the core problem in the analyst's own words."
    },
    "requirements": {
      "type": "object",
      "additionalProperties": false,
      "required": [
        "functional",
        "nonFunctional",
        "inputConstraints",
        "outputConstraints",
        "assumptions",
        "ambiguities",
        "edgeCases"
      ],
      "properties": {
        "functional": {
          "type": "array",
          "description": "What the solution must do.",
          "items": { "$ref": "#/$defs/requirementItem" }
        },
        "nonFunctional": {
          "type": "array",
          "description": "Quality attributes: performance, memory, scalability, reliability, etc.",
          "items": { "$ref": "#/$defs/requirementItem" }
        },
        "inputConstraints": {
          "type": "array",
          "description": "Explicit constraints on the input (ranges, sizes, formats).",
          "items": { "$ref": "#/$defs/constraintItem" }
        },
        "outputConstraints": {
          "type": "array",
          "description": "Required output format, precision, ordering, or special values.",
          "items": { "$ref": "#/$defs/constraintItem" }
        },
        "assumptions": {
          "type": "array",
          "description": "Assumptions made where the statement is silent.",
          "items": { "type": "string" }
        },
        "ambiguities": {
          "type": "array",
          "description": "Unclear or underspecified points that need clarification.",
          "items": { "type": "string" }
        },
        "edgeCases": {
          "type": "array",
          "description": "Boundary and corner cases the solution must handle.",
          "items": { "type": "string" }
        }
      }
    },
    "problemTree": {
      "$ref": "#/$defs/treeNode",
      "description": "Hierarchical decomposition rooted at the core problem."
    }
  },
  "$defs": {
    "requirementItem": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "description"],
      "properties": {
        "id": { "type": "string", "description": "Stable id, e.g. FR1, NFR2." },
        "description": { "type": "string" },
        "priority": { "type": "string", "enum": ["must", "should", "could"] }
      }
    },
    "constraintItem": {
      "type": "object",
      "additionalProperties": false,
      "required": ["description"],
      "properties": {
        "name": { "type": "string", "description": "Variable or field the constraint applies to." },
        "description": { "type": "string", "description": "The constraint, including ranges/limits." }
      }
    },
    "treeNode": {
      "type": "object",
      "additionalProperties": false,
      "required": ["id", "label", "kind"],
      "properties": {
        "id": { "type": "string", "description": "Unique node id used in the Mermaid diagram." },
        "label": { "type": "string", "description": "Human-readable node text." },
        "kind": {
          "type": "string",
          "enum": [
            "root",
            "subProblem",
            "requirement",
            "inputConstraint",
            "outputConstraint",
            "edgeCase",
            "assumption"
          ]
        },
        "children": {
          "type": "array",
          "items": { "$ref": "#/$defs/treeNode" }
        }
      }
    }
  }
}

