python -c "import re,json; t=open(r'd:\ps2 tri\inputs\problem.txt',encoding='utf-8').read(); d=json.loads(re.search(r'```json\n(.*?)\n```',t,re.S).group(1)); s=json.load(open(r'd:\ps2 tri\schema\problem-tree.schema.json',encoding='utf-8'));
try:
    import jsonschema; jsonschema.validate(d,s); print('SCHEMA VALID')
except ImportError:
    print('jsonschema not installed; skipping (JSON already parsed OK)')
except Exception as e:
    print('SCHEMA ERROR:', e)"
